+    let lower = raw.trim().to_ascii_lowercase();
+    let mut parts = lower.split('x');
+    let w = parts.next()?.trim().parse::<u32>().ok()?;
+    let h = parts.next()?.trim().parse::<u32>().ok()?;
+    if parts.next().is_some() || w == 0 || h == 0 {
+        return None;
+    }
+    Some((w, h))
+}
